def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        base_priority = 0
        if ratio >= 3:
            base_priority = 3000 + (ratio - 3) * 500
        elif 2 <= ratio < 3:
            base_priority = 1000 + (ratio - 2) * 300
        elif 1.5 <= ratio < 2:
            base_priority = 600 + (ratio - 1.5) * 200
        elif 1 < ratio < 1.5:
            base_priority = 400 + (ratio - 1) * 150
        elif ratio == 1:
            base_priority = 200
        else:
            score = 0
            for j in range(1, 15):
                temp = ((capacity - item) ** j) / (capacity ** j)
                if temp < 0.03:
                    score += temp * 150 / j
                elif temp < 0.15:
                    score += temp * 30 / (j ** 0.5)
                elif temp < 0.5:
                    score += temp * 10 / (j ** 1.5)
                else:
                    score += temp * 2 / (j ** 2)
            score_adjustment = 0
            for k in range(1, 6):
                score_adjustment += ((item / (capacity + k*0.5)) ** (k + 1)) * 15 / (k + 2)
            base_priority = 1 / (score + 1e-6) + score_adjustment
        if capacity - item < 0.2 * capacity:
            base_priority += ((capacity - item) ** 2) / (capacity * 10)
        if item > capacity * 0.85:
            base_priority *= 0.85
        if i % 3 == 0:
            base_priority += 2 / (capacity + 2)
            if i % 2 == 0:
                base_priority += (item % (capacity + 1)) / (capacity + 1)
            else:
                base_priority -= (item % (capacity + 1)) / (capacity + 1)
        elif i % 3 == 1:
            base_priority -= 1.5 / (capacity + 3)
            for m in range(1, 4):
                base_priority += ((item / (capacity + m)) ** m) * 5 / (m + 1)
        else:
            base_priority += 1 / (capacity + 5)
            if item < capacity * 0.5:
                for n in range(1, 3):
                    base_priority -= (capacity - item) / ((capacity + n) ** 2)
        if capacity < item * 1.2 and capacity > item:
            base_priority *= 0.95 + 0.05 * (capacity / (item * 1.2))
        priorities[i] = base_priority
    return priorities
